#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#ifdef RD_WG_SIZE_0_0
        #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define BLOCK_SIZE RD_WG_SIZE
#else
        #define BLOCK_SIZE 16
#endif

void lud_diagonal_omp(float *m, int matrix_dim, int offset)
{
  int i, j;
  float shadow[BLOCK_SIZE][BLOCK_SIZE];
  int tid;
  int array_offset;

  #pragma omp parallel
  {
    tid = omp_get_thread_num();
    array_offset = offset*matrix_dim+offset;

    #pragma omp barrier
    for(i=0; i < BLOCK_SIZE; i++){
      shadow[i][tid]=m[array_offset+tid];
      array_offset += matrix_dim;
    }
    #pragma omp barrier

    for(i=0; i < BLOCK_SIZE-1; i++) {
      if (tid>i){
        for(j=0; j < i; j++)
          shadow[tid][i] -= shadow[tid][j]*shadow[j][i];
        shadow[tid][i] /= shadow[i][i];
      }
      #pragma omp barrier

      if (tid>i){
        for(j=0; j < i+1; j++)
          shadow[i+1][tid] -= shadow[i+1][j]*shadow[j][tid];
      }
      #pragma omp barrier
    }

    array_offset = (offset+1)*matrix_dim+offset;
    #pragma omp barrier
    for(i=1; i < BLOCK_SIZE; i++){
      m[array_offset+tid]=shadow[i][tid];
      array_offset += matrix_dim;
    }
  }
}

void lud_perimeter_omp(float *m, int matrix_dim, int offset, int block_idx)
{
  float dia[BLOCK_SIZE][BLOCK_SIZE];
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];
  int i, j, array_offset;
  int idx, tid;

  #pragma omp parallel
  {
    tid = omp_get_thread_num();

    if (tid < BLOCK_SIZE) {
      idx = tid;

      array_offset = offset*matrix_dim+offset;
      for (i=0; i < BLOCK_SIZE/2; i++){
        dia[i][idx]=m[array_offset+idx];
        array_offset += matrix_dim;
      }

      array_offset = offset*matrix_dim+offset;
      for (i=0; i < BLOCK_SIZE; i++) {
        peri_row[i][idx]=m[array_offset+(block_idx+1)*BLOCK_SIZE+idx];
        array_offset += matrix_dim;
      }
    } else {
      idx = tid-BLOCK_SIZE;

      array_offset = (offset+BLOCK_SIZE/2)*matrix_dim+offset;
      for (i=BLOCK_SIZE/2; i < BLOCK_SIZE; i++){
        dia[i][idx]=m[array_offset+idx];
        array_offset += matrix_dim;
      }

      array_offset = (offset+(block_idx+1)*BLOCK_SIZE)*matrix_dim+offset;
      for (i=0; i < BLOCK_SIZE; i++) {
        peri_col[idx][i] = m[array_offset+idx];
        array_offset += matrix_dim;
      }
    }
    #pragma omp barrier

    if (tid < BLOCK_SIZE) { 
      idx=tid;
      for(i=1; i < BLOCK_SIZE; i++){
        for (j=0; j < i; j++)
          peri_row[i][idx]-=dia[i][j]*peri_row[j][idx];
      }
    } else { 
      idx=tid - BLOCK_SIZE;
      for(i=0; i < BLOCK_SIZE; i++){
        for(j=0; j < i; j++)
          peri_col[idx][i]-=peri_col[idx][j]*dia[j][i];
        peri_col[idx][i] /= dia[i][i];
      }
    }

    #pragma omp barrier

    if (tid < BLOCK_SIZE) { 
      idx=tid;
      array_offset = (offset+1)*matrix_dim+offset;
      for(i=1; i < BLOCK_SIZE; i++){
        m[array_offset+(block_idx+1)*BLOCK_SIZE+idx] = peri_row[i][idx];
        array_offset += matrix_dim;
      }
    } else { 
      idx=tid - BLOCK_SIZE;
      array_offset = (offset+(block_idx+1)*BLOCK_SIZE)*matrix_dim+offset;
      for(i=0; i < BLOCK_SIZE; i++){
        m[array_offset+idx] =  peri_col[i][idx];
        array_offset += matrix_dim;
      }
    }
  }
}

void lud_internal_omp(float *m, int matrix_dim, int offset, int block_idx_x, int block_idx_y)
{
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];
  int i;
  float sum;
  int global_row_id, global_col_id;
  int tid_x, tid_y;

  #pragma omp parallel
  {
    tid_x = omp_get_thread_num() % BLOCK_SIZE;
    tid_y = omp_get_thread_num() / BLOCK_SIZE;

    global_row_id = offset + (block_idx_y+1)*BLOCK_SIZE;
    global_col_id = offset + (block_idx_x+1)*BLOCK_SIZE;

    peri_row[tid_y][tid_x] = m[(offset+tid_y)*matrix_dim+global_col_id+tid_x];
    peri_col[tid_y][tid_x] = m[(global_row_id+tid_y)*matrix_dim+offset+tid_x];

    #pragma omp barrier

    sum = 0;
    for (i=0; i < BLOCK_SIZE; i++)
      sum += peri_col[tid_y][i] * peri_row[i][tid_x];
    m[(global_row_id+tid_y)*matrix_dim+global_col_id+tid_x] -= sum;
  }
}

void lud_omp(float *m, int matrix_dim)
{
  int i, j, k;
  int block_idx_x, block_idx_y;

  for (i=0; i < matrix_dim-BLOCK_SIZE; i += BLOCK_SIZE) {
      lud_diagonal_omp(m, matrix_dim, i);

      for (k=0; k < (matrix_dim-i)/BLOCK_SIZE-1; k++) {
        lud_perimeter_omp(m, matrix_dim, i, k);
      }

      for (j=0; j < (matrix_dim-i)/BLOCK_SIZE-1; j++) {
        for (k=0; k < (matrix_dim-i)/BLOCK_SIZE-1; k++) {
          lud_internal_omp(m, matrix_dim, i, k, j);
        }
      }
  }
  lud_diagonal_omp(m, matrix_dim, i);
}
